import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Home from './Home';
import Login from './Login';
import Register from './Register';
import Questions from './Questions';
import QuestionDetail from './QuestionDetail';
import './App.css';
import { AppBar, Toolbar, Typography, Button, Box, Snackbar, Alert } from '@mui/material';

function App() {
  const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'success' });

  // Hàm dùng để hiển thị snackbar từ các component con (có thể truyền qua context hoặc props nếu muốn mở rộng)
  const showSnackbar = (message, severity = 'success') => {
    setSnackbar({ open: true, message, severity });
  };

  return (
    <Router>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" component={Link} to="/" sx={{ flexGrow: 1, color: 'inherit', textDecoration: 'none' }}>
            Diễn đàn SV
          </Typography>
          <Button color="inherit" component={Link} to="/questions">Câu hỏi</Button>
          <Button color="inherit" component={Link} to="/login">Đăng nhập</Button>
          <Button color="inherit" component={Link} to="/register">Đăng ký</Button>
        </Toolbar>
      </AppBar>
      <Box sx={{ mt: 2 }}>
        <Routes>
          <Route path="/" element={<Home showSnackbar={showSnackbar} />} />
          <Route path="/login" element={<Login showSnackbar={showSnackbar} />} />
          <Route path="/register" element={<Register showSnackbar={showSnackbar} />} />
          <Route path="/questions" element={<Questions showSnackbar={showSnackbar} />} />
          <Route path="/questions/:id" element={<QuestionDetail showSnackbar={showSnackbar} />} />
        </Routes>
      </Box>
      <Snackbar
        open={snackbar.open}
        autoHideDuration={3000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      >
        <Alert onClose={() => setSnackbar({ ...snackbar, open: false })} severity={snackbar.severity} sx={{ width: '100%' }}>
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Router>
  );
}

export default App;
